import{_ as e,o as l,c as i,a2 as r}from"./chunks/framework.m9rfQn3T.js";const u=JSON.parse('{"title":"前端项目负责人需要具有的能力","description":"","frontmatter":{"title":"前端项目负责人需要具有的能力","date":"2021-06-24T20:57:44.000Z","permalink":"/pages/a7133b8247d7b/","categories":["面试题","项目"],"tags":[null]},"headers":[],"relativePath":"10.面试题/44.项目/10.前端项目负责人需要具有的能力.md","filePath":"10.面试题/44.项目/10.前端项目负责人需要具有的能力.md","lastUpdated":1782538095000}'),t={name:"10.面试题/44.项目/10.前端项目负责人需要具有的能力.md"};function o(h,a,n,s,p,d){return l(),i("div",null,[...a[0]||(a[0]=[r('<p>抛开技术，前端的视野有多么重要</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210031.png" alt="20210624210031"></p><p>&lt;!-- more --&gt;</p><h2 id="技术能力" tabindex="-1">技术能力 <a class="header-anchor" href="#技术能力" aria-label="Permalink to &quot;技术能力&quot;">​</a></h2><p>基本的日常开发需求。前端技术体系。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210125.png" alt="20210624210125"></p><h3 id="快速掌握和上手新技术的能力" tabindex="-1">快速掌握和上手新技术的能力 <a class="header-anchor" href="#快速掌握和上手新技术的能力" aria-label="Permalink to &quot;快速掌握和上手新技术的能力&quot;">​</a></h3><h3 id="指导和帮助初级同学解决问题" tabindex="-1">指导和帮助初级同学解决问题 <a class="header-anchor" href="#指导和帮助初级同学解决问题" aria-label="Permalink to &quot;指导和帮助初级同学解决问题&quot;">​</a></h3><p>这个环节不能缺失，这里就要求技术全面和思想指导。当在帮助初级同学解决问题的时候，不是仅仅只是在给他们解决问题，更重要的一点是双方之间在进行技术沟通和思路解决方案。对大家都有提升。</p><ul><li>提升负责人的技术全面性，和沟通能力，问题解决能力</li><li>提升初级同学的知识面，了解其他人对于这个问题的思考</li></ul><h2 id="规划能力" tabindex="-1">规划能力 <a class="header-anchor" href="#规划能力" aria-label="Permalink to &quot;规划能力&quot;">​</a></h2><p>规划能力，在于负责人对于工作的计划规划，是不是胸有成竹。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210237.png" alt="20210624210237"></p><h3 id="技术体系规划" tabindex="-1">技术体系规划 <a class="header-anchor" href="#技术体系规划" aria-label="Permalink to &quot;技术体系规划&quot;">​</a></h3><h4 id="选型考虑" tabindex="-1">选型考虑 <a class="header-anchor" href="#选型考虑" aria-label="Permalink to &quot;选型考虑&quot;">​</a></h4><ul><li>是否可以满足业务需求</li><li>当前团队熟系技术栈的难易程度</li><li>当前技术体系搭配相关的技术体系</li><li>亲自去玩一玩，看看</li></ul><h4 id="相关技术文档的输出" tabindex="-1">相关技术文档的输出 <a class="header-anchor" href="#相关技术文档的输出" aria-label="Permalink to &quot;相关技术文档的输出&quot;">​</a></h4><p>在调研新技术的时候，形成技术文档输出的习惯，可以将一些坑或者使用方法，记录下来</p><h3 id="人力资源规划" tabindex="-1">人力资源规划 <a class="header-anchor" href="#人力资源规划" aria-label="Permalink to &quot;人力资源规划&quot;">​</a></h3><h4 id="人力梯度规划" tabindex="-1">人力梯度规划 <a class="header-anchor" href="#人力梯度规划" aria-label="Permalink to &quot;人力梯度规划&quot;">​</a></h4><p>根据项目的体量，复杂度，需要规划具体的高中初级几人。</p><ul><li>复杂度 决定高中级人数</li><li>体量决定初级人数</li></ul><h4 id="人力数量安排" tabindex="-1">人力数量安排 <a class="header-anchor" href="#人力数量安排" aria-label="Permalink to &quot;人力数量安排&quot;">​</a></h4><p>肯定存在重复性劳动动作，这部分具体的数量安排。</p><h3 id="任务划分规划" tabindex="-1">任务划分规划 <a class="header-anchor" href="#任务划分规划" aria-label="Permalink to &quot;任务划分规划&quot;">​</a></h3><ul><li>任务难易程度 划分不同的开发人员</li><li>可复用性考虑</li><li>任务时间安排</li></ul><p>前面两个决定具体的时间划分。</p><h3 id="风险规划" tabindex="-1">风险规划 <a class="header-anchor" href="#风险规划" aria-label="Permalink to &quot;风险规划&quot;">​</a></h3><ul><li>任务完成量</li><li>任务完成度</li></ul><p>风险分为两种：任务完成了多少，任务完成的怎么样。<br><strong>开发完成</strong>和<strong>任务完成</strong>是两回事情。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210333.png" alt="20210624210333"></p><h3 id="突发情况应对能力" tabindex="-1">突发情况应对能力 <a class="header-anchor" href="#突发情况应对能力" aria-label="Permalink to &quot;突发情况应对能力&quot;">​</a></h3><p>其实正常情况下不会出现这种情况，但是在人力条件下，可能出现这种情况。借助现有的资源，解决相对的问题。</p><h2 id="业务能力" tabindex="-1">业务能力 <a class="header-anchor" href="#业务能力" aria-label="Permalink to &quot;业务能力&quot;">​</a></h2><p>前端同学其实对于业务能力因为各种原因，普遍没有后端了解的多。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210407.png" alt="20210624210407"></p><h3 id="梳理业务流程" tabindex="-1">梳理业务流程 <a class="header-anchor" href="#梳理业务流程" aria-label="Permalink to &quot;梳理业务流程&quot;">​</a></h3><p>利用泳道图或者流程图去梳理业务流程</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210557.png" alt="20210624210557"></p><h3 id="业务关键字段和数据在我们系统上的体现" tabindex="-1">业务关键字段和数据在我们系统上的体现 <a class="header-anchor" href="#业务关键字段和数据在我们系统上的体现" aria-label="Permalink to &quot;业务关键字段和数据在我们系统上的体现&quot;">​</a></h3><p>关键字段和数据是基于业务逻辑流程梳理之后，知道对接接口的时候，一些关键数据的重要意义。</p><h3 id="有效的参与业务评审-考虑业务和技术实现的结合" tabindex="-1">有效的参与业务评审，考虑业务和技术实现的结合 <a class="header-anchor" href="#有效的参与业务评审-考虑业务和技术实现的结合" aria-label="Permalink to &quot;有效的参与业务评审，考虑业务和技术实现的结合&quot;">​</a></h3><p>不是将业务评审当成是一个过场，需要有自己的思考，以及梳理，别人的讲解始终都是别人的，如果自己不了解，是无法在开发过程中了解业务实现是否有问题。</p><p>具体如何参与业务评审，后面会有其他的培训。</p><h2 id="协作能力" tabindex="-1">协作能力 <a class="header-anchor" href="#协作能力" aria-label="Permalink to &quot;协作能力&quot;">​</a></h2><p>协作能力，分为两个部分。一个是项目团队，一个是部门团队。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210531.png" alt="20210624210531"></p><h3 id="和项目团队" tabindex="-1">和项目团队 <a class="header-anchor" href="#和项目团队" aria-label="Permalink to &quot;和项目团队&quot;">​</a></h3><h4 id="开发维度" tabindex="-1">开发维度 <a class="header-anchor" href="#开发维度" aria-label="Permalink to &quot;开发维度&quot;">​</a></h4><p>这里的几个部分后面会有专门的 session 大家一起探讨。</p><ul><li>产品评审</li><li>后端联调</li><li>交付测试验收</li></ul><h4 id="前端小团队" tabindex="-1">前端小团队 <a class="header-anchor" href="#前端小团队" aria-label="Permalink to &quot;前端小团队&quot;">​</a></h4><ul><li>任务分配</li><li>任务 check</li><li>任务风险</li></ul><p><strong>合理分配，及时 check，预知风险</strong></p><h4 id="管理维度" tabindex="-1">管理维度 <a class="header-anchor" href="#管理维度" aria-label="Permalink to &quot;管理维度&quot;">​</a></h4><ul><li>项目经理 沟通 任务进度</li><li>汇报风险 &amp; 以及应对</li><li>周报工作体现</li></ul><p>总结</p><ul><li><strong>汇报人：项目经理</strong></li><li><strong>汇报内容：进度和风向</strong></li><li><strong>汇报方式：周报</strong></li></ul><h3 id="和部门团队" tabindex="-1">和部门团队 <a class="header-anchor" href="#和部门团队" aria-label="Permalink to &quot;和部门团队&quot;">​</a></h3><p>因为在我们公司，前端部门是一种虚线的状态，大家可能分步在不同的项目组里面，但是前端还是要从整体技术方向上去做统一的提升和信息共享。</p><ul><li>统一技术栈</li><li>配置化开发协作</li><li>信息共享，插件或者业务组件沉淀，节省其他项目成本</li></ul><p><strong>组件沉淀</strong></p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210628.png" alt="20210624210628"></p><p><strong>业务沉淀</strong></p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210648.png" alt="20210624210648"></p><h2 id="沟通能力" tabindex="-1">沟通能力 <a class="header-anchor" href="#沟通能力" aria-label="Permalink to &quot;沟通能力&quot;">​</a></h2><p>沟通能力可以体现一个人的思维方式，以及是不是有着自己的表达方式。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210711.png" alt="20210624210711"></p><h3 id="表达方式" tabindex="-1">表达方式 <a class="header-anchor" href="#表达方式" aria-label="Permalink to &quot;表达方式&quot;">​</a></h3><p>表达方式决定是不是 在有效沟通，有的时候可能大家沟通了半天还不是在讲一个东西。</p><p><strong>谈任何问题的时候，不要直接上来讲问题，将上下文同步清除，然后在进行沟通。</strong></p><p>为什么有的时候在讲一些问题的时候，讲了半天没有重点，听得稀里糊涂，就是因为自己本身就没有将问题梳理好，就直接拿出来讲。</p><p>任何事情：都是会有<strong>输入 -》过程 -》输出</strong>。</p><p>那我们将输入，输出讲清楚，中间哪个过程出了问题，就直接将前因后果的上下文自己理清楚，然后清楚的表达出来。</p><h3 id="表达对象重点" tabindex="-1">表达对象重点 <a class="header-anchor" href="#表达对象重点" aria-label="Permalink to &quot;表达对象重点&quot;">​</a></h3><ul><li>项目经理，领导汇报工作：重点是进度和风险，细节不必特别强调。</li><li>部门人员：主要在于共享信息，和人力资源风险。</li><li>团队人员：和内部团队人员沟通则是要，大的方向同步好，细节一定不能放过。因为着重于技术的实现。</li></ul><h3 id="输入输出" tabindex="-1">输入输出 <a class="header-anchor" href="#输入输出" aria-label="Permalink to &quot;输入输出&quot;">​</a></h3><p>我们在和不同的人沟通的输入不同，输出也不同。</p><ul><li>输出指的是：我们想要达到的目的。</li><li>输入指的是：我们需要传到给对方的信息。</li></ul><h2 id="判断能力" tabindex="-1">判断能力 <a class="header-anchor" href="#判断能力" aria-label="Permalink to &quot;判断能力&quot;">​</a></h2><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210735.png" alt="20210624210735"></p><p>判断能力决定于，一个人是否已经可以全局把控项目。判断能力在于有底气在项目当中对于事项进行判断和决策。</p><h2 id="框架能力" tabindex="-1">框架能力 <a class="header-anchor" href="#框架能力" aria-label="Permalink to &quot;框架能力&quot;">​</a></h2><p>框架能力决定一个人是否可以处理项目当中非业务逻辑的处理能力。</p><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210752.png" alt="20210624210752"></p><h3 id="分析问题-解决问题能力" tabindex="-1">分析问题，解决问题能力 <a class="header-anchor" href="#分析问题-解决问题能力" aria-label="Permalink to &quot;分析问题，解决问题能力&quot;">​</a></h3><p>这一个东西极为重要，这是一个人的综合能力的体现。</p><p>技术广度，深度，逻辑分析能力【一部分结构化思维】的体现。</p><h2 id="架构能力" tabindex="-1">架构能力 <a class="header-anchor" href="#架构能力" aria-label="Permalink to &quot;架构能力&quot;">​</a></h2><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210815.png" alt="20210624210815"></p><h2 id="心理能力" tabindex="-1">心理能力 <a class="header-anchor" href="#心理能力" aria-label="Permalink to &quot;心理能力&quot;">​</a></h2><p><img src="https://gcore.jsdelivr.net/gh/wu529778790/image/blog/20210624210831.png" alt="20210624210831"></p><p>关于心理能力，这里没有和上面放在一起，但是也提一下，因为团队当中之前有同学和我反映过一些心理活动。</p><p>场景：可能我们在计划任务的时候，一切都计划好了，但是最终的结果还是延期了。可能有各方面的原因。团队人不愿意加班，联调没有很好的完成，前期技术方案没有很好的实现，或者有问题。然后感觉自己是不是不行。产生了自我的认知否定。</p><p><em>我们不能决定所有的事情，事情也不一定会按照我们设想的去发展。我们唯一能做的就是，把我们需要做的事情做好，至于结果可能有所偏离，那我们继续努力就好。不必针对我们自身，产生不好的情绪。</em></p><p><strong>尽人事，知天命。</strong></p><p>所以我们更注重是做好自己的事情，遇到的情绪有自己的情绪处理方式。</p><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="https://juejin.cn/post/6946210273061502990" target="_blank" rel="noreferrer">https://juejin.cn/post/6946210273061502990</a></li></ul>',99)])])}const g=e(t,[["render",o]]);export{u as __pageData,g as default};
